CREATE TABLE public.payment_logs ( id uuid DEFAULT uuid_generate_v4() PRIMARY KEY, center_id uuid NOT NULL REFERENCES public.centers(id), order_id VARCHAR(120), payment_id VARCHAR(120), amount decimal(10, 2) NOT NULL, status text NOT NULL DEFAULT 'PENDING' CHECK (status IN ('PENDING', 'SUCCESS', 'FAILED')), created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now() ); 
